 {"id":"bd-3sy","title":"Implement RequestResponseRenderer for traffic visualization","description":"## Purpose and Rationale

Create a renderer that displays JSON-RPC request/response traffic in a beautiful, readable format. This is invaluable for debugging and understanding what's happening in real-time.

## Background

When debugging MCP servers, seeing the actual requests and responses is crucial. Raw JSON is hard to read; a formatted display with syntax highlighting, timing info, and clear request/response pairing makes debugging much easier.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/client/traffic.rs

use rich_rust::{Panel, Rule, Style};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::protocol::{JsonRpcRequest, JsonRpcResponse};
use std::time::{Duration, Instant};

/// Renders request/response traffic beautifully
pub struct RequestResponseRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
    show_params: bool,
    show_result: bool,
    truncate_at: usize,
    show_timing: bool,
}

impl RequestResponseRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            theme,
            context,
            show_params: true,
            show_result: true,
            truncate_at: 200,
            show_timing: true,
        }
    }

    /// Render an incoming request
    pub fn render_request(&self, request: &JsonRpcRequest, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_request_plain(request, console);
            return;
        }

        let method_style = self.method_style(&request.method);

        // Request header
        console.print(&format!(
            "\n[bold]→[/] [{}]{}[/] [dim]id={}[/]",
            method_style,
            request.method,
            self.format_id(&request.id)
        ));

        // Parameters (if enabled and present)
        if self.show_params {
            if let Some(params) = &request.params {
                self.render_json_preview("Params", params, console);
            }
        }
    }

    /// Render an outgoing response
    pub fn render_response(
        &self, 
        response: &JsonRpcResponse, 
        duration: Option<Duration>,
        console: &FastMcpConsole
    ) {
        if !self.context.should_use_rich() {
            self.render_response_plain(response, duration, console);
            return;
        }

        // Determine response type and style
        let (icon, status, style) = if response.error.is_some() {
            ("✗", "error", self.theme.error_style().to_markup())
        } else {
            ("✓", "ok", self.theme.success_style().to_markup())
        };

        // Response header
        let timing = if self.show_timing {
            duration.map(|d| format!(" [dim]({})[/]", self.format_duration(d)))
                .unwrap_or_default()
        } else {
            String::new()
        };

        console.print(&format!(
            "[bold]←[/] [{}]{} {}[/] [dim]id={}[/]{}",
            style,
            icon,
            status,
            self.format_id(&response.id),
            timing
        ));

        // Result or error
        if self.show_result {
            if let Some(error) = &response.error {
                self.render_error_preview(error, console);
            } else if let Some(result) = &response.result {
                self.render_json_preview("Result", result, console);
            }
        }
    }

    /// Render a request/response pair together
    pub fn render_pair(
        &self,
        request: &JsonRpcRequest,
        response: &JsonRpcResponse,
        duration: Duration,
        console: &FastMcpConsole,
    ) {
        if !self.context.should_use_rich() {
            self.render_pair_plain(request, response, duration, console);
            return;
        }

        // Combined display
        let status_icon = if response.error.is_some() { "✗" } else { "✓" };
        let status_style = if response.error.is_some() {
            self.theme.error_style().to_markup()
        } else {
            self.theme.success_style().to_markup()
        };

        console.print(&format!(
            "[bold cyan]{}[/] [{}]{}[/] [dim]{}[/]",
            request.method,
            status_style,
            status_icon,
            self.format_duration(duration)
        ));
    }

    fn render_json_preview(&self, label: &str, value: &serde_json::Value, console: &FastMcpConsole) {
        let json_str = serde_json::to_string_pretty(value).unwrap_or_default();
        let preview = self.truncate_string(&json_str);

        console.print(&format!("  [dim]{}:[/]", label));
        for line in preview.lines() {
            console.print(&format!("    [dim]{}[/]", line));
        }
    }

    fn render_error_preview(&self, error: &JsonRpcError, console: &FastMcpConsole) {
        console.print(&format!(
            "  [red]Error {}[/]: {}",
            error.code,
            error.message
        ));

        if let Some(data) = &error.data {
            console.print(&format!("  [dim]Data: {}[/]", self.truncate_string(&data.to_string())));
        }
    }

    fn method_style(&self, method: &str) -> String {
        // Color-code by method category
        if method.starts_with("tools/") {
            "cyan"
        } else if method.starts_with("resources/") {
            "green"
        } else if method.starts_with("prompts/") {
            "magenta"
        } else if method.starts_with("initialize") || method.starts_with("shutdown") {
            "yellow"
        } else {
            "white"
        }.to_string()
    }

    fn format_id(&self, id: &Option<serde_json::Value>) -> String {
        id.as_ref()
            .map(|v| v.to_string())
            .unwrap_or_else(|| "null".to_string())
    }

    fn format_duration(&self, d: Duration) -> String {
        let micros = d.as_micros();
        if micros < 1000 {
            format!("{}μs", micros)
        } else if micros < 1_000_000 {
            format!("{:.1}ms", micros as f64 / 1000.0)
        } else {
            format!("{:.2}s", micros as f64 / 1_000_000.0)
        }
    }

    fn truncate_string(&self, s: &str) -> String {
        if s.len() <= self.truncate_at {
            s.to_string()
        } else {
            format!("{}...", &s[..self.truncate_at])
        }
    }

    fn render_request_plain(&self, request: &JsonRpcRequest, console: &FastMcpConsole) {
        console.print(&format!("-> {} (id={})", request.method, self.format_id(&request.id)));
    }

    fn render_response_plain(&self, response: &JsonRpcResponse, duration: Option<Duration>, console: &FastMcpConsole) {
        let status = if response.error.is_some() { "error" } else { "ok" };
        let timing = duration.map(|d| format!(" ({})", self.format_duration(d))).unwrap_or_default();
        console.print(&format!("<- {} (id={}){}", status, self.format_id(&response.id), timing));
    }

    fn render_pair_plain(&self, request: &JsonRpcRequest, response: &JsonRpcResponse, duration: Duration, console: &FastMcpConsole) {
        let status = if response.error.is_some() { "FAIL" } else { "OK" };
        console.print(&format!("{} [{}] {}", request.method, status, self.format_duration(duration)));
    }
}
