 {"id":"bd-5gw","title":"Implement ToolTableRenderer for tool registry display","description":"## Purpose and Rationale

Create a renderer that displays registered tools in a beautiful table format using rich_rust. This helps developers and operators quickly see what capabilities a server exposes.

## Background

MCP servers expose tools that clients can call. Seeing the complete list of tools with their descriptions, parameters, and types in a well-formatted table is essential for understanding what a server can do. This is particularly useful during development and debugging.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/handlers/tool_table.rs

use rich_rust::{Table, Column, Panel, JustifyMethod, Style};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::tool::ToolInfo;

/// Renders tool registry as beautiful tables
pub struct ToolTableRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
    show_parameters: bool,
    show_return_type: bool,
    max_description_width: usize,
}

impl ToolTableRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            theme,
            context,
            show_parameters: true,
            show_return_type: true,
            max_description_width: 50,
        }
    }

    /// Render a collection of tools as a table
    pub fn render(&self, tools: &[ToolInfo], console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(tools, console);
            return;
        }

        if tools.is_empty() {
            console.print("[dim]No tools registered[/]");
            return;
        }

        let mut table = Table::new()
            .title(format!("📦 Registered Tools ({})", tools.len()))
            .with_column(Column::new("Name").style(self.theme.primary_style()))
            .with_column(Column::new("Description").max_width(self.max_description_width))
            .with_column(Column::new("Parameters").justify(JustifyMethod::Center));

        if self.show_return_type {
            table = table.with_column(Column::new("Returns"));
        }

        for tool in tools {
            let name = &tool.name;
            let desc = self.truncate_description(&tool.description);
            let params = self.format_parameters(&tool.parameters);

            if self.show_return_type {
                let returns = self.format_return_type(&tool.return_type);
                table.add_row_cells([name.as_str(), &desc, &params, &returns]);
            } else {
                table.add_row_cells([name.as_str(), &desc, &params]);
            }
        }

        console.print_renderable(&table);
    }

    /// Render a single tool in detail
    pub fn render_detail(&self, tool: &ToolInfo, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_detail_plain(tool, console);
            return;
        }

        // Tool name header
        console.print(&format!("\n[bold cyan]{}[/]", tool.name));
        console.print(&format!("[dim]{}[/]\n", tool.description));

        // Parameters table
        if !tool.parameters.is_empty() {
            let mut param_table = Table::new()
                .title("Parameters")
                .with_column(Column::new("Name").style(self.theme.primary_style()))
                .with_column(Column::new("Type"))
                .with_column(Column::new("Required").justify(JustifyMethod::Center))
                .with_column(Column::new("Description"));

            for param in &tool.parameters {
                let required = if param.required { "✓" } else { "" };
                param_table.add_row_cells([
                    param.name.as_str(),
                    &param.type_name,
                    required,
                    &param.description.as_deref().unwrap_or(""),
                ]);
            }

            console.print_renderable(&param_table);
        }

        // Return type
        if let Some(ret) = &tool.return_type {
            console.print(&format!("\n[dim]Returns:[/] {}", ret));
        }
    }

    fn format_parameters(&self, params: &[ParameterInfo]) -> String {
        if params.is_empty() {
            "none".to_string()
        } else {
            let required = params.iter().filter(|p| p.required).count();
            let optional = params.len() - required;

            match (required, optional) {
                (r, 0) => format!("{} required", r),
                (0, o) => format!("{} optional", o),
                (r, o) => format!("{} required, {} optional", r, o),
            }
        }
    }

    fn truncate_description(&self, desc: &str) -> String {
        if desc.len() <= self.max_description_width {
            desc.to_string()
        } else {
            format!("{}...", &desc[..self.max_description_width - 3])
        }
    }

    fn format_return_type(&self, ret: &Option<String>) -> String {
        ret.as_deref().unwrap_or("-").to_string()
    }

    fn render_plain(&self, tools: &[ToolInfo], console: &FastMcpConsole) {
        console.print(&format!("Registered Tools ({})", tools.len()));
        console.print(&"=".repeat(40));
        for tool in tools {
            console.print(&format!("  {} - {}", tool.name, tool.description));
        }
    }

    fn render_detail_plain(&self, tool: &ToolInfo, console: &FastMcpConsole) {
        console.print(&format!("Tool: {}", tool.name));
        console.print(&format!("Description: {}", tool.description));
        for param in &tool.parameters {
            let req = if param.required { "required" } else { "optional" };
            console.print(&format!("  - {}: {} ({})", param.name, param.type_name, req));
        }
    }
}
