#[test]
fn test_concurrent_updates() {
    let stats = ServerStats::new();
    let stats_clone = stats.clone();

    std::thread::spawn(move || {
        for _ in 0..1000 {
            stats_clone.record_request("tools/call", Duration::from_millis(10), true);
        }
    });

    for _ in 0..1000 {
        stats.record_request("resources/read", Duration::from_millis(5), true);
    }

    // Wait and verify
    std::thread::sleep(Duration::from_millis(100));
